	}
}

void calculate_sig_T( int nuc, double E, Input input, SimulationData data, RSComplex * sigTfactors )
{
	double phi;

	for( int i = 0; i < 4; i++ )
	{
		phi = data.pseudo_K0RS[nuc * input.numL + i] * sqrt(E);

		if( i == 1 )
			phi -= - atan( phi );
		else if( i == 2 )
			phi -= atan( 3.0 * phi / (3.0 - phi*phi));
		else if( i == 3 )
			phi -= atan(phi*(15.0-phi*phi)/(15.0-6.0*phi*phi));

		phi *= 2.0;

		sigTfactors[i].r = cos(phi);
		sigTfactors[i].i = -sin(phi);
	}
}

void calculate_micro_xs( double * micro_xs, int nuc, double E, Input input, SimulationData data)
{
	double sigT;
	double sigA;
	double sigF;
	double sigE;

	double spacing = 1.0 / data.n_windows[nuc];
	int window = (int) ( E / spacing );
	if( window == data.n_windows[nuc] )
		window--;

	RSComplex sigTfactors[4]; 
	calculate_sig_T(nuc, E, input, data, sigTfactors );

	Window w = data.windows[nuc * data.max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	for( int i = w.start; i < w.end; i++ )
	{
		RSComplex PSIIKI;
		RSComplex CDUM;
		Pole pole = data.poles[nuc * data.max_num_poles + i];
		RSComplex t1 = {0, 1};
		RSComplex t2 = {sqrt(E), 0 };
		PSIIKI = c_div( t1 , c_sub(pole.MP_EA,t2) );
		RSComplex E_c = {E, 0};
		CDUM = c_div(PSIIKI, E_c);
		sigT += (c_mul(pole.MP_RT, c_mul(CDUM, sigTfactors[pole.l_value])) ).r;
		sigA += (c_mul( pole.MP_RA, CDUM)).r;
		sigF += (c_mul(pole.MP_RF, CDUM)).r;
	}

	sigE = sigT - sigA;

	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

void calculate_micro_xs_doppler( double * micro_xs, int nuc, double E, Input input, SimulationData data )
{
	double sigT;
	double sigA;
	double sigF;
	double sigE;

	double spacing = 1.0 / data.n_windows[nuc];
	int window = (int) ( E / spacing );
	if( window == data.n_windows[nuc] )
		window--;

	RSComplex sigTfactors[4]; 
	calculate_sig_T(nuc, E, input, data, sigTfactors );

	Window w = data.windows[nuc * data.max_num_windows + window];
	sigT = E * w.T;
	sigA = E * w.A;
	sigF = E * w.F;

	double dopp = 0.5;

	for( int i = w.start; i < w.end; i++ )
	{
		Pole pole = data.poles[nuc * data.max_num_poles + i];

		RSComplex E_c = {E, 0};
		RSComplex dopp_c = {dopp, 0};
		RSComplex Z = c_mul(c_sub(E_c, pole.MP_EA), dopp_c);

		RSComplex faddeeva = fast_nuclear_W( Z );

		sigT += (c_mul( pole.MP_RT, c_mul(faddeeva, sigTfactors[pole.l_value]) )).r;
		sigA += (c_mul( pole.MP_RA , faddeeva)).r;
		sigF += (c_mul( pole.MP_RF , faddeeva)).r;
	}

	sigE = sigT - sigA;

	micro_xs[0] = sigT;
	micro_xs[1] = sigA;
	micro_xs[2] = sigF;
	micro_xs[3] = sigE;
}

void calculate_macro_xs( double * macro_xs, int mat, double E, Input input, SimulationData data ) 
{
	for( int i = 0; i < 4; i++ )
		macro_xs[i] = 0;

	for( int i = 0; i < data.num_nucs[mat]; i++ )
	{
		double micro_xs[4];
		int nuc = data.mats[mat * data.max_num_nucs + i];

		if( input.doppler == 1 )
			calculate_micro_xs_doppler( micro_xs, nuc, E, input, data);
		else
			calculate_micro_xs( micro_xs, nuc, E, input, data);

		for( int j = 0; j < 4; j++ )
		{
			macro_xs[j] += micro_xs[j] * data.concs[mat * data.max_num_nucs + i];
		}
	}
}

int pick_mat( uint64_t * seed )
{
	double dist[12];
	dist[0]  = 0.140;	
	dist[1]  = 0.052;	
	dist[2]  = 0.275;	
	dist[3]  = 0.134;	
	dist[4]  = 0.154;	
	dist[5]  = 0.064;	
	dist[6]  = 0.066;	
	dist[7]  = 0.055;	
	dist[8]  = 0.008;	
	dist[9]  = 0.015;	
	dist[10] = 0.025;	
	dist[11] = 0.013;	

	double roll = LCG_random_double(seed);

	for( int i = 0; i < 12; i++ )
	{
		double running = 0;
		for( int j = i; j > 0; j-- )
			running += dist[j];
		if( roll < running )
			return i;
	}

	return 0;
}

void run_event_based_simulation(Input input, SimulationData data, unsigned long * vhash_result )
{
	printf("Running baseline event-based simulation...\n");

	unsigned long local_hash = 0;

	#pragma omp parallel
	{
		unsigned long thread_hash = 0;

		#pragma omp for
		for( int i = 0; i < input.lookups; i++ )
		{
			uint64_t local_seed = STARTING_SEED;
			local_seed = fast_forward_LCG(local_seed, 2*i);

			double E = LCG_random_double(&local_seed);
			int mat  = pick_mat(&local_seed);

			double macro_xs[4] = {0};

			calculate_macro_xs( macro_xs, mat, E, input, data );

			double max = -DBL_MAX;
			int max_idx = 0;
			for(int x = 0; x < 4; x++ )
			{
				if( macro_xs[x] > max )
				{
					max = macro_xs[x];
					max_idx = x;
				}
			}
			thread_hash += (max_idx+1);
		}
		#pragma omp critical
		local_hash += thread_hash;
	}

	*vhash_result = local_hash;
}

void run_event_based_simulation_optimization_1(Input in, SimulationData data, unsigned long * vhash_result)
{
	const char * optimization_name = "Optimization 1 - Material & Energy Sorts + Material-specific Kernels";

	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	printf("Allocating additional data required by kernel...\n");
	size_t sz;
	size_t total_sz = 0;

	sz = in.lookups * sizeof(double);
	data.p_energy_samples = (double *) malloc(sz);
	total_sz += sz;
	data.length_p_energy_samples = in.lookups;

	sz = in.lookups * sizeof(int);
	data.mat_samples = (int *) malloc(sz);
	total_sz += sz;
	data.length_mat_samples = in.lookups;

	printf("Allocated an additional %.0lf MB of data.\n", total_sz/1024.0/1024.0);

	printf("Beginning optimized simulation...\n");

	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t local_seed = STARTING_SEED;
		local_seed = fast_forward_LCG(local_seed, 2*i);

		double p_energy = LCG_random_double(&local_seed);
		int mat         = pick_mat(&local_seed); 

		data.p_energy_samples[i] = p_energy;
		data.mat_samples[i] = mat;
	}

	int n_lookups_per_material[12];
	for( int m = 0; m < 12; m++ )
		n_lookups_per_material[m] = 0;

	for( int i = 0; i < in.lookups; i++ )
		n_lookups_per_material[data.mat_samples[i]]++;

	int * sorted_indices = (int *) malloc(in.lookups * sizeof(int));
	int * current_pos = (int *) calloc(12, sizeof(int));

	for( int m = 0; m < 12; m++ )
	{
		for( int i = 0; i < in.lookups; i++ )
		{
			if( data.mat_samples[i] == m )
			{
				sorted_indices[current_pos[m]++] = i;
			}
		}
	}

	for( int m = 0; m < 12; m++ )
	{
		int start = 0;
		for( int prev = 0; prev < m; prev++ )
			start += n_lookups_per_material[prev];

		int count = n_lookups_per_material[m];

		for( int i = 0; i < count - 1; i++ )
		{
			for( int j = i + 1; j < count; j++ )
			{
				int idx_i = sorted_indices[start + i];
				int idx_j = sorted_indices[start + j];
				if( data.p_energy_samples[idx_i] > data.p_energy_samples[idx_j] )
				{
					int tmp = sorted_indices[start + i];
					sorted_indices[start + i] = sorted_indices[start + j];
					sorted_indices[start + j] = tmp;
				}
			}
		}
	}

	unsigned long local_hash = 0;

	#pragma omp parallel
	{
		unsigned long thread_hash = 0;

		#pragma omp for
		for( int m = 0; m < 12; m++ )
		{
			int start_idx = 0;
			for( int prev = 0; prev < m; prev++ )
				start_idx += n_lookups_per_material[prev];

			int count = n_lookups_per_material[m];

			for( int k = 0; k < count; k++ )
			{
				int i = sorted_indices[start_idx + k];
				int mat = data.mat_samples[i];
				if( mat != m ) continue;

				double macro_xs[4] = {0};

				calculate_macro_xs( macro_xs, mat, data.p_energy_samples[i], in, data );

				double max = -DBL_MAX;
				int max_idx = 0;
				for(int x = 0; x < 4; x++ )
				{
					if( macro_xs[x] > max )
					{
						max = macro_xs[x];
						max_idx = x;
					}
				}
				thread_hash += (max_idx+1);
			}
		}
		#pragma omp critical
		local_hash += thread_hash;
	}

	free(sorted_indices);
	free(current_pos);

	*vhash_result = local_hash;
}

void run_history_based_simulation(Input input, SimulationData data, unsigned long * vhash_result )
{
	printf("History-based simulation not implemented in OpenMP offload code. Instead,\nuse the event-based method with \"-m event\" argument.\n");
	exit(1);
}

int main(int argc, char * argv[])
{
	int version = 13;
	double start, stop;

	Input input = read_CLI( argc, argv );

	omp_set_num_threads(input.nthreads);

	logo(version);
	center_print("INPUT SUMMARY", 79);
	border_print();
	print_input_summary(input);

	border_print();
	center_print("INITIALIZATION", 79);
	border_print();

	start = get_time();

	SimulationData SD = initialize_simulation( input );

	stop = get_time();

	printf("Initialization Complete. (%.2lf seconds)\n", stop-start);

	border_print();
	center_print("SIMULATION", 79);
	border_print();

	unsigned long vhash = 0;

	start = get_time();

	if( input.simulation_method == EVENT_BASED )
	{
		if( input.kernel_id == 0 )
			run_event_based_simulation(input, SD, &vhash );
		else if( input.kernel_id == 1 )
			run_event_based_simulation_optimization_1(input, SD, &vhash );
		else
		{
			printf("Error: No kernel ID %d found!\n", input.kernel_id);
			exit(1);
		}
	}
	else if( input.simulation_method == HISTORY_BASED )
	{
		printf("History-based simulation not implemented in OpenMP offload code. Instead,\nuse the event-based method with \"-m event\" argument.\n");
		exit(1);
	}

	stop = get_time();

	vhash = vhash % 999983;

	printf("Simulation Complete.\n");

	border_print();
	center_print("RESULTS", 79);
	border_print();

	int is_invalid = validate_and_print_results(input, stop-start, vhash);

	border_print();

	return is_invalid;
}

